const sharedToken = env.get('PROXMOX_SHARED_TOKEN') || '__SET_PROXMOX_SHARED_TOKEN__';
const forgejoBase = (env.get('FORGEJO_BASE_URL') || '__SET_FORGEJO_BASE_URL__').replace(/\/+$/, '');
const forgejoOwner = env.get('FORGEJO_OWNER') || '__SET_FORGEJO_OWNER__';
const forgejoRepo = env.get('FORGEJO_REPO') || '__SET_FORGEJO_REPO__';
const forgejoBranch = env.get('FORGEJO_BRANCH') || 'main';
const forgejoApiToken = env.get('FORGEJO_API_TOKEN') || '__SET_FORGEJO_API_TOKEN__';

const missing = [sharedToken, forgejoBase, forgejoOwner, forgejoRepo, forgejoApiToken].filter(v => String(v).startsWith('__SET_'));
if (missing.length) {
    msg.statusCode = 500;
    msg.payload = { ok: false, error: 'relay not configured', missing: ['PROXMOX_SHARED_TOKEN', 'FORGEJO_BASE_URL', 'FORGEJO_OWNER', 'FORGEJO_REPO', 'FORGEJO_API_TOKEN'] };
    return [null, msg];
}

const incoming = (msg.req && msg.req.headers && msg.req.headers['x-proxmox-token']) || '';
if (incoming !== sharedToken) {
    msg.statusCode = 401;
    msg.payload = { ok: false, error: 'unauthorized' };
    return [null, msg];
}

let body = msg.payload;
if (typeof body === 'string') {
    try {
        body = JSON.parse(body);
    } catch (err) {
        msg.statusCode = 400;
        msg.payload = { ok: false, error: 'invalid json', detail: err.message };
        return [null, msg];
    }
}
if (!body || typeof body !== 'object') {
    msg.statusCode = 400;
    msg.payload = { ok: false, error: 'invalid body' };
    return [null, msg];
}

const source = body.source || (((msg.req && msg.req.path) || '').includes('/pbs') ? 'pbs' : 'pve');
const tsSeconds = Number(body.timestamp || Math.floor(Date.now() / 1000));
const ts = new Date(tsSeconds * 1000);
if (Number.isNaN(ts.getTime())) {
    msg.statusCode = 400;
    msg.payload = { ok: false, error: 'invalid timestamp' };
    return [null, msg];
}

const pad = v => String(v).padStart(2, '0');
const yyyy = ts.getUTCFullYear();
const mm = pad(ts.getUTCMonth() + 1);
const dd = pad(ts.getUTCDate());
const hh = pad(ts.getUTCHours());
const mi = pad(ts.getUTCMinutes());
const ss = pad(ts.getUTCSeconds());
const stamp = `${yyyy}${mm}${dd}T${hh}${mi}${ss}Z`;

const safe = (value, fallback) => {
    const cleaned = String(value || fallback || 'unknown')
        .replace(/[^a-zA-Z0-9._-]+/g, '-')
        .replace(/^-+|-+$/g, '')
        .slice(0, 80);
    return cleaned || fallback || 'unknown';
};

const fields = body.fields || {};
const host = safe(fields.hostname || fields.node || fields.datastore || 'unknown-host', 'unknown-host');
const kind = safe(fields.type || fields['job-type'] || fields['job-id'] || 'notification', 'notification');
const severity = safe(body.severity || 'unknown', 'unknown');
const nonce = Math.random().toString(16).slice(2, 8);
const repoPath = `events/${source}/${yyyy}/${mm}/${dd}/${stamp}_${host}_${kind}_${severity}_${nonce}.json`;

const archive = {
    received_at: new Date().toISOString(),
    source,
    title: body.title || '',
    message: body.message || '',
    severity: body.severity || 'unknown',
    timestamp: body.timestamp || null,
    fields
};

msg._archiveKind = 'notification';
msg._archivePath = repoPath;
msg.method = 'POST';
msg.url = `${forgejoBase}/api/v1/repos/${forgejoOwner}/${forgejoRepo}/contents/${repoPath}`;
msg.headers = {
    Authorization: `token ${forgejoApiToken}`,
    'Content-Type': 'application/json',
    Accept: 'application/json'
};
msg.payload = {
    branch: forgejoBranch,
    message: `Archive Proxmox ${source.toUpperCase()} notification ${stamp}`,
    content: Buffer.from(JSON.stringify(archive, null, 2) + '\n').toString('base64')
};
return [msg, null];

const sharedToken = env.get('PROXMOX_SHARED_TOKEN') || '__SET_PROXMOX_SHARED_TOKEN__';
const forgejoBase = (env.get('FORGEJO_BASE_URL') || '__SET_FORGEJO_BASE_URL__').replace(/\/+$/, '');
const forgejoOwner = env.get('FORGEJO_OWNER') || '__SET_FORGEJO_OWNER__';
const forgejoRepo = env.get('FORGEJO_REPO') || '__SET_FORGEJO_REPO__';
const forgejoBranch = env.get('FORGEJO_BRANCH') || 'main';
const forgejoApiToken = env.get('FORGEJO_API_TOKEN') || '__SET_FORGEJO_API_TOKEN__';

const missing = [sharedToken, forgejoBase, forgejoOwner, forgejoRepo, forgejoApiToken].filter(v => String(v).startsWith('__SET_'));
if (missing.length) {
    msg.statusCode = 500;
    msg.payload = { ok: false, error: 'relay not configured', missing: ['PROXMOX_SHARED_TOKEN', 'FORGEJO_BASE_URL', 'FORGEJO_OWNER', 'FORGEJO_REPO', 'FORGEJO_API_TOKEN'] };
    return [null, msg];
}

const incoming = (msg.req && msg.req.headers && msg.req.headers['x-proxmox-token']) || '';
if (incoming !== sharedToken) {
    msg.statusCode = 401;
    msg.payload = { ok: false, error: 'unauthorized' };
    return [null, msg];
}

let body = msg.payload;
if (typeof body === 'string') {
    try {
        body = JSON.parse(body);
    } catch (err) {
        msg.statusCode = 400;
        msg.payload = { ok: false, error: 'invalid json', detail: err.message };
        return [null, msg];
    }
}
if (!body || typeof body !== 'object') {
    msg.statusCode = 400;
    msg.payload = { ok: false, error: 'invalid body' };
    return [null, msg];
}

const reqPath = (msg.req && msg.req.path) || '';
const source = body.source || (reqPath.includes('/pbs') ? 'pbs' : 'pve');
const logText = body.log_text || body.log || body.payload;
if (typeof logText !== 'string' || !logText.trim()) {
    msg.statusCode = 400;
    msg.payload = { ok: false, error: 'missing log_text' };
    return [null, msg];
}

const safe = (value, fallback) => {
    const cleaned = String(value || fallback || 'unknown')
        .replace(/[^a-zA-Z0-9._:@-]+/g, '-')
        .replace(/^-+|-+$/g, '')
        .slice(0, 120);
    return cleaned || fallback || 'unknown';
};

const taskObj = body.task && typeof body.task === 'object' ? body.task : {};
const upid = safe(body.upid || body.task_id || taskObj.upid || taskObj.id || 'unknown-upid', 'unknown-upid');
const nodeName = safe(body.node || body.hostname || taskObj.node || `${source}-node`, `${source}-node`);
const taskType = safe(body.task_type || body.worker_type || taskObj.worker_type || body.kind || 'task', 'task');
const status = safe(body.status || body.exitstatus || taskObj.status || 'unknown', 'unknown');

const rawTs = Number(body.ended_at || body.endtime || body.end_time || body.timestamp || body.started_at || body.starttime || body.start_time || taskObj.endtime || taskObj.starttime || Math.floor(Date.now() / 1000));
const ts = new Date(rawTs * 1000);
if (Number.isNaN(ts.getTime())) {
    msg.statusCode = 400;
    msg.payload = { ok: false, error: 'invalid timestamp' };
    return [null, msg];
}

const pad = v => String(v).padStart(2, '0');
const yyyy = ts.getUTCFullYear();
const mm = pad(ts.getUTCMonth() + 1);
const dd = pad(ts.getUTCDate());
const hh = pad(ts.getUTCHours());
const mi = pad(ts.getUTCMinutes());
const ss = pad(ts.getUTCSeconds());
const stamp = `${yyyy}${mm}${dd}T${hh}${mi}${ss}Z`;
const repoPath = `task-logs/${source}/${yyyy}/${mm}/${dd}/${stamp}_${nodeName}_${taskType}_${status}_${upid}.log`;

msg._archiveKind = 'tasklog';
msg._archivePath = repoPath;
msg._archiveUpid = upid;
msg.method = 'POST';
msg.url = `${forgejoBase}/api/v1/repos/${forgejoOwner}/${forgejoRepo}/contents/${repoPath}`;
msg.headers = {
    Authorization: `token ${forgejoApiToken}`,
    'Content-Type': 'application/json',
    Accept: 'application/json'
};
msg.payload = {
    branch: forgejoBranch,
    message: `Archive Proxmox ${source.toUpperCase()} task log ${stamp} ${upid}`,
    content: Buffer.from(logText.endsWith('\n') ? logText : (logText + '\n')).toString('base64')
};
return [msg, null];

const kind = msg._archiveKind || 'archive';
if (msg.statusCode >= 200 && msg.statusCode < 300) {
    const response = msg.payload || {};
    msg.payload = {
        ok: true,
        kind,
        path: msg._archivePath || null,
        upid: msg._archiveUpid || null,
        forgejo_status: msg.statusCode,
        commit_url: response.commit && response.commit.html_url ? response.commit.html_url : null
    };
    return [msg, null];
}

const forgejoStatus = msg.statusCode;
let err = 'forgejo write failed';
if (msg.payload && typeof msg.payload === 'object' && msg.payload.message) {
    err = msg.payload.message;
}
if (forgejoStatus === 422 && String(err).toLowerCase().includes('already exists')) {
    msg.statusCode = 200;
    msg.payload = {
        ok: true,
        existed: true,
        kind,
        path: msg._archivePath || null,
        upid: msg._archiveUpid || null,
        forgejo_status: forgejoStatus
    };
    return [msg, null];
}
msg.statusCode = 502;
msg.payload = {
    ok: false,
    kind,
    error: err,
    path: msg._archivePath || null,
    upid: msg._archiveUpid || null,
    forgejo_status: forgejoStatus || null,
    response: msg.payload
};
return [null, msg];
